const now = new Date();
console.log(now.getMilliseconds() )
var time = window.document.getElementById('timer')
// Counting the Second with the browser
let seconds = 0;

setInterval(() => {
  seconds++;
  console.log((seconds/100).toFixed(2));
  time.innerHTML = `${seconds} seconds`;
}, 1000);